    fetchedAt: Date.now(),
    label: precision === "coarse" ? "手机当前位置（大概区域）" : "手机当前位置"
  };

  // ====== 新增：逆地理编码 ======
  try {
    const geoRes = await fetch(
      `https://restapi.amap.com/v3/geocode/regeo?location=${rawLon},${rawLat}&key=你的高德key&radius=100&extensions=base`
    );
    const geoData = await geoRes.json();
    if (geoData.status === "1" && geoData.regeocode) {
      out.address = geoData.regeocode.formatted_address || null;
      const comp = geoData.regeocode.addressComponent || {};
      out.province = comp.province || null;
      out.city = comp.city || null;
      out.district = comp.district || null;
      out.neighborhood = comp.neighborhood?.name || null;
    }
