.app-screen.wechat{
  background:
    var(--miao-soft-bg) center/cover no-repeat,
    linear-gradient(180deg,#FFFFFF 0%,#FFF8FA 100%)!important;
}
.app-screen.wechat .statusbar{
  background:rgba(255,229,237,.95)!important;
  color:#684A3D!important;
}
.app-screen.wechat .statusbar:after{
  content:"";
  position:absolute;
  left:0;right:0;bottom:-13px;
  height:18px;
  pointer-events:none;
  background:radial-gradient(circle at 16px 18px, transparent 15px, rgba(255,229,237,.95) 16px) 0 0/32px 18px repeat-x;
  opacity:.95;
}
.app-screen.wechat .wechat-head{
  background:transparent!important;
  border-bottom:0!important;
  box-shadow:none!important;
  padding-top:calc(12px + env(safe-area-inset-top))!important;
}
.app-screen.wechat .profile-title{
  color:#684A3D!important;
  font-weight:950!important;
  letter-spacing:.035em;
}
.app-screen.wechat .profile-sub{color:color-mix(in srgb,#684A3D 55%,transparent)!important}
.app-screen.wechat .chat{
  background:transparent!important;
  padding-left:13px!important;
  padding-right:13px!important;
}
.app-screen.wechat .msg{
  margin:8px 0!important;
}
.app-screen.wechat .avatar{
  width:34px!important;
  height:34px!important;
  border:2px solid rgba(255,255,255,.75)!important;
  box-shadow:0 4px 10px rgba(92,61,48,.06)!important;
}
.app-screen.wechat .bubble{
  position:relative;
  box-shadow:none!important;
  line-height:1.42!important;
  font-weight:700;
  letter-spacing:.005em;
  padding:7px 11px!important;
  border-radius:18px!important;
  max-width:100%!important;
}
.app-screen.wechat .msg.role .bubble{
  background:#FFFFFF!important;
  color:#67493D!important;
  border:1.4px solid #F3D4DD!important;
  border-top-left-radius:13px!important;
  border-bottom-left-radius:17px!important;
}
.app-screen.wechat .msg.user .bubble{
  background:#FCE4EC!important;
  color:#67493D!important;
  border:1.4px solid #F2D0DA!important;
  border-top-right-radius:13px!important;
  border-bottom-right-radius:17px!important;
}
.app-screen.wechat .msg.role .bubble:before{
  content:"";
  position:absolute;
  left:-11px;top:7px;
  width:18px;height:14px;
  background:var(--miao-role-tail) center/contain no-repeat;
  z-index:-1;
}
.app-screen.wechat .msg.user .bubble:after{
  content:"";
  position:absolute;
  right:-11px;top:7px;
  width:18px;height:14px;
  background:var(--miao-user-tail) center/contain no-repeat;
  z-index:-1;
}
.app-screen.wechat .time-line,
.app-screen.wechat .name-line{
  color:#AAA0A0!important;
  font-weight:700!important;
}
.app-screen.wechat .composer-wrap{
  background:rgba(255,229,237,.95)!important;
  border-top:0!important;
  box-shadow:0 -8px 24px rgba(92,61,48,.035)!important;
  padding-top:5px!important;
}
.app-screen.wechat .composer-wrap:before{
  content:"";
  position:absolute;
  left:0;right:0;top:-13px;
  height:18px;
  pointer-events:none;
  background:radial-gradient(circle at 16px 0px, transparent 15px, rgba(255,229,237,.95) 16px) 0 0/32px 18px repeat-x;
}
.app-screen.wechat .composer{
  align-items:center!important;
  padding:7px 10px 9px!important;
}
.app-screen.wechat .composer textarea{
  min-height:39px!important;
  max-height:104px!important;
  border:none!important;
  outline:none!important;
  border-radius:999px!important;
  background:var(--miao-input-frame) center/100% 100% no-repeat!important;
  color:#684A3D!important;
  padding:9px 15px!important;
  box-shadow:none!important;
}
.app-screen.wechat .composer textarea::placeholder{
  color:color-mix(in srgb,#684A3D 42%,transparent)!important;
  opacity:1!important;
}
.app-screen.wechat .toolbar .chip-btn{
  background:rgba(255,255,255,.36)!important;
  color:#684A3D!important;
  border:1px solid rgba(255,255,255,.35)!important;
}
.app-screen.wechat .send-btn,
.app-screen.wechat .call-btn{
  background:color-mix(in srgb,#EFC8D4 82%,#fff 18%)!important;
  color:#fff!important;
  border:1px solid rgba(255,255,255,.42)!important;
  box-shadow:none!important;
}

